namespace sv_d1541cf49f7a4f2e9487d7232544dfb5.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Reusable textarea + button input for sending messages or replies *@

<div class="message-input">
    <textarea @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="btn btn-primary btn-sm" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = "";

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSubmit.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #dee2e6;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ced4da;
    border-radius: 6px;
    padding: 0.5rem;
    font-size: 0.875rem;
    font-family: inherit;
}

.message-input textarea:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.15);
}

.message-input button {
    align-self: flex-end;
}

@* A small popup with common emoji reactions *@

<div class="emoji-picker">
    @foreach (var emoji in Emojis)
    {
        <button class="emoji-btn" @onclick="() => Select(emoji)" title="@emoji">@emoji</button>
    }
</div>

@code {
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] Emojis = ["👍", "❤️", "😂", "🎉", "😮", "😢"];

    private async Task Select(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

.emoji-picker {
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 0.35rem 0.5rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    position: absolute;
    bottom: 100%;
    right: 0;
    margin-bottom: 0.25rem;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 0.15rem 0.3rem;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Services

@if (Reactions?.Count > 0)
{
    <div class="reaction-bar">
        @foreach (var reaction in Reactions)
        {
            <button class="reaction-badge" @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)"
                    title="@string.Join(", ", reaction.Users)">
                <span class="reaction-emoji">@reaction.Emoji</span>
                <span class="reaction-count">@reaction.Users.Count</span>
            </button>
        }
    </div>
}

@code {
    [Parameter] public List<Reaction>? Reactions { get; set; }
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

.reaction-bar {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.35rem;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    background: #f0f4ff;
    border: 1px solid #d0d7e6;
    border-radius: 12px;
    padding: 0.1rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
    line-height: 1.4;
}

.reaction-badge:hover {
    background: #dde4f0;
    border-color: #b0bdd0;
}

.reaction-emoji {
    font-size: 0.95rem;
}

.reaction-count {
    font-weight: 600;
    color: #555;
}

@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Services

<div class="message-item @(IsThreadStarter ? "thread-starter" : "")"
     @onmouseenter="() => _hovered = true"
     @onmouseleave="OnMouseLeave">

    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (IsThreadStarter && ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😊
            </button>
            @if (_showEmojiPicker)
            {
                <EmojiPicker OnEmojiSelected="HandleEmojiPicked" />
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReaction { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiPicked(string emoji)
    {
        _showEmojiPicker = false;
        await OnReaction.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReaction.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

.message-item {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    transition: background 0.15s;
}

.message-item:hover {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1d1c1d;
}

.message-time {
    font-size: 0.75rem;
    color: #8e8e8e;
}

.message-content {
    font-size: 0.9rem;
    color: #1d1c1d;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 0.2rem 0;
    margin-top: 0.25rem;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -0.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.15rem 0.25rem;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    font-size: 1rem;
    cursor: pointer;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

