arguments.file_text:
@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Services

<div class="message-list" @onscroll="HandleScroll" @ref="_listRef">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages...</div>
    }
    @foreach (var msg in Messages)
    {
        var threadInfo = ThreadSummaries.GetValueOrDefault(msg.Id);
        <MessageItem Message="msg"
                     IsThreadStarter="msg.ReplyToId is null && threadInfo is not null"
                     ReplyCount="@(threadInfo?.ReplyCount ?? 0)"
                     OnOpenThread="OnOpenThread"
                     OnReaction="OnReaction" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReaction { get; set; }

    private ElementReference _listRef;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ScrollToBottom();
        }
    }

    private async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("eval", "document.querySelector('[data-scroll-bottom]')?.scrollTo(0, document.querySelector('[data-scroll-bottom]').scrollHeight)");
        }
        catch (JSDisconnectedException) { }
    }

    private async Task HandleScroll()
    {
        // Detect scroll-to-top to trigger pagination
        try
        {
            var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[data-scroll-bottom]')?.scrollTop ?? 1");
            if (scrollTop < 50 && !IsLoadingMore)
            {
                await OnLoadMore.InvokeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.loading-indicator {
    text-align: center;
    padding: 0.75rem;
    font-size: 0.8rem;
    color: #8e8e8e;
}

@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-name-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelect { get; set; }

    private async Task HandleClick() => await OnSelect.InvokeAsync(Channel.Id);

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "..." : desc;
}

.channel-item {
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 0.35rem;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.2);
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #fff;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    border-radius: 10px;
    padding: 0.1rem 0.45rem;
    min-width: 1.2rem;
    text-align: center;
    line-height: 1.3;
}

.channel-desc {
    font-size: 0.75rem;
    color: rgba(255, 255, 255, 0.6);
    margin-top: 0.1rem;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
}

@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Services

<div class="channel-sidebar">
