@page "/chat"
@rendermode InteractiveServer
@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Services
@using sv_d1541cf49f7a4f2e9487d7232544dfb5.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main">
        @if (_activeChannel is not null)
        {
            <div class="chat-main-header">
                <h5># @_activeChannel.Name</h5>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <MessageList Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         IsLoadingMore="_isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReaction="HandleReaction" />

            <MessageInput Placeholder="@($"Message #{_activeChannel.Name}")"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="chat-empty">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnReplySubmit="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];
    private bool _isLoadingMore;
    private int _skip;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _messages = [];
        CloseThreadSync();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_activeChannelId is null || _isLoadingMore) return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            _skip += older.Count;
            BuildThreadSummaries();
        }

        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local reaction list
        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        var replies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplies = replies.Where(r => r.Id != rootMessageId).ToList();
        _threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadSync();
    }

    private void CloseThreadSync()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary count
        if (_threadSummaries.TryGetValue(_threadRootMessage.Id, out var summary))
        {
            _threadSummaries[_threadRootMessage.Id] = summary with
            {
                ReplyCount = summary.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
                _threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }
}

.chat-layout {
    display: flex;
    height: calc(100vh - 7rem);
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.chat-sidebar {
    flex: 0 0 20%;
    min-width: 200px;
    max-width: 280px;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    overflow: hidden;
}

.chat-thread {
    flex: 0 0 25%;
    min-width: 260px;
    max-width: 360px;
}

.chat-main-header {
    padding: 0.65rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #fff;
}

.chat-main-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #1d1c1d;
}

.channel-description {
    font-size: 0.8rem;
    color: #8e8e8e;
}

.chat-empty {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8e8e8e;
    font-size: 0.95rem;
}

