        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        var replies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplies = replies.Where(r => r.Id != rootMessageId).ToList();
        _threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadSync();
    }

    private void CloseThreadSync()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary count
        if (_threadSummaries.TryGetValue(_threadRootMessage.Id, out var summary))
        {
            _threadSummaries[_threadRootMessage.Id] = summary with
            {
                ReplyCount = summary.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
                _threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }
}

