toolArgs.file_text:
.chat-layout {
    display: flex;
    height: calc(100vh - 7rem);
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.chat-sidebar {
    flex: 0 0 20%;
    min-width: 200px;
    max-width: 280px;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    overflow: hidden;
}

.chat-thread {
    flex: 0 0 25%;
    min-width: 260px;
    max-width: 360px;
}

.chat-main-header {
    padding: 0.65rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #fff;
}

.chat-main-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #1d1c1d;
}

.channel-description {
    font-size: 0.8rem;
    color: #8e8e8e;
}

.chat-empty {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8e8e8e;
    font-size: 0.95rem;
}

