<div class="message-list" @ref="_listRef">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages...</div>
    }
    @foreach (var msg in Messages)
    {
        var threadInfo = ThreadSummaries.GetValueOrDefault(msg.Id);
        <MessageItem Message="msg"
                     IsThreadStarter="msg.ReplyToId is null && threadInfo is not null"
                     ReplyCount="@(threadInfo?.ReplyCount ?? 0)"
                     OnOpenThread="OnOpenThread"
                     OnReaction="OnReaction" />
    }
</div>

@code {
