    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReaction { get; set; }

    private ElementReference _listRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<MessageList>? _selfRef;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private int _lastMessageCount;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-d1541cf49f7a4f2e9487d7232544dfb5/Components/Chat/MessageList.razor.js");
            _selfRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("init", _listRef, _selfRef);
        }

        if (Messages.Count != _lastMessageCount)
        {
            _lastMessageCount = Messages.Count;
            if (_module is not null)
            {
                await _module.InvokeVoidAsync("scrollToBottom", _listRef);
            }
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (!IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose", _listRef);
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _selfRef?.Dispose();
    }
}

